+    #[test]
+    fn scrub_detects_corruption_after_write_churn_dirties_symbols() {
+        // Simulate write churn dirtying symbols, then scrub: corruption must
+        // still be detected (no false "clean" outcome).
+        let cx = Cx::for_testing();
+        let block_size = 256;
