+        // Group should be clean after refresh.
+        assert!(!pipeline.is_group_dirty(GroupNumber(0)));
+
+        // Now inject corruption after symbols are fresh.
+        drop(pipeline);
+        device
+            .write_block(&cx, BlockNumber(4), &vec![0xAB; block_size as usize])
